  3→import { useState, useRef } from 'react'
  4→import type { Contact } from '@/lib/types'
  5→
  6→const AVATAR_COLORS = ['#e0d4f7', '#d4e8f7', '#d4f0e8', '#f7e8d4', '#f7d4d4', '#f0f7d4']
  7→function avatarColor(name: string) {
  8→  let h = 0; for (const c of name) h = (h * 31 + c.charCodeAt(0)) % AVATAR_COLORS.length
  9→  return AVATAR_COLORS[h]
 10→}
 11→function initials(name: string) {
 12→  return name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2)
 13→}
 14→function daysSince(dateStr?: string): number | null {
 15→  if (!dateStr) return null
 16→  const d = new Date(dateStr)
 17→  if (isNaN(d.getTime())) return null
 18→  return Math.floor((Date.now() - d.getTime()) / 86400000)
 19→}
