 21→type Column = { id: string; label: string; tags: string[] }
 22→
 23→const DEFAULT_COLUMNS: Column[] = [
 24→  { id: 'partner', label: 'Partners', tags: ['partner', 'sponsor'] },
 25→  { id: 'warm', label: 'Warm', tags: ['warm'] },
 26→  { id: 'investor', label: 'Investors / VCs', tags: ['investor', 'vc'] },
 27→  { id: 'community', label: 'Community', tags: ['community'] },
 28→  { id: 'other', label: 'Other', tags: [] },
 29→]
 30→
 31→function assignColumn(contact: Contact, columns: Column[]): string {
 32→  const tags = (contact.tags || []).map((t) => t.toLowerCase())
 33→  for (const col of columns) {
 34→    if (col.tags.length === 0) continue
 35→    if (col.tags.some((t) => tags.includes(t))) return col.id
 36→  }
 37→  return 'other'
 38→}
