 40→export default function KanbanView({
 41→  contacts,
 42→  selectedId,
 43→  onSelect,
 44→  onMoveContact,
 45→}: {
 46→  contacts: Contact[]
 47→  selectedId: string | null
 48→  onSelect: (c: Contact) => void
 49→  onMoveContact: (contactId: string, newTags: string[]) => void
 50→}) {
 51→  const [columns, setColumns] = useState<Column[]>(DEFAULT_COLUMNS)
 52→  const [editingColId, setEditingColId] = useState<string | null>(null)
 53→  const [editingLabel, setEditingLabel] = useState('')
 54→  const [dragOverColId, setDragOverColId] = useState<string | null>(null)
 55→  const dragContactRef = useRef<Contact | null>(null)
 56→
 57→  const grouped: Record<string, Contact[]> = {}
 58→  for (const col of columns) grouped[col.id] = []
 59→  for (const c of contacts) grouped[assignColumn(c, columns)].push(c)
 60→
 61→  function startEditCol(col: Column) {
 62→    setEditingColId(col.id)
 63→    setEditingLabel(col.label)
 64→  }
 65→
 66→  function saveColLabel(colId: string) {
 67→    if (editingLabel.trim()) {
 68→      setColumns((cols) => cols.map((c) => c.id === colId ? { ...c, label: editingLabel.trim() } : c))
 69→    }
 70→    setEditingColId(null)
 71→  }
 72→
 73→  function onDragStart(contact: Contact) {
 74→    dragContactRef.current = contact
 75→  }
 76→
 77→  function onDragOver(e: React.DragEvent, colId: string) {
 78→    e.preventDefault()
 79→    setDragOverColId(colId)
 80→  }
 81→
 82→  function onDrop(e: React.DragEvent, col: Column) {
 83→    e.preventDefault()
 84→    setDragOverColId(null)
 85→    const contact = dragContactRef.current
 86→    if (!contact) return
 87→    const currentColId = assignColumn(contact, columns)
 88→    if (currentColId === col.id) return
 89→
 90→    // Build new tags: remove tags that match any column, add the target column's first tag
 91→    const allColTags = columns.flatMap((c) => c.tags)
 92→    const keptTags = (contact.tags || []).filter((t) => !allColTags.includes(t.toLowerCase()))
 93→
 94→    let newTags: string[]
 95→    if (col.tags.length === 0) {
 96→      // "Other" column — just remove column tags
 97→      newTags = keptTags
 98→    } else {
 99→      newTags = [...keptTags, col.tags[0]]
100→    }
101→
102→    onMoveContact(contact.id, newTags)
103→    dragContactRef.current = null
104→  }
105→
106→  function onDragLeave() {
107→    setDragOverColId(null)
108→  }
109→
110→  return (
111→    <div className="flex-1 overflow-x-auto overflow-y-hidden">
112→      <div className="flex gap-4 h-full p-6 min-w-max">
113→        {columns.map((col) => (
114→          <div
115→            key={col.id}
116→            className={`w-64 shrink-0 flex flex-col rounded-xl transition-colors ${dragOverColId === col.id ? 'bg-[#f0ede8]' : ''}`}
117→            onDragOver={(e) => onDragOver(e, col.id)}
118→            onDrop={(e) => onDrop(e, col)}
119→            onDragLeave={onDragLeave}
120→          >
121→            <div className="flex items-center justify-between mb-3 px-1">
122→              {editingColId === col.id ? (
123→                <input
124→                  autoFocus
125→                  value={editingLabel}
126→                  onChange={(e) => setEditingLabel(e.target.value)}
127→                  onBlur={() => saveColLabel(col.id)}
128→                  onKeyDown={(e) => {
129→                    if (e.key === 'Enter') saveColLabel(col.id)
130→                    if (e.key === 'Escape') setEditingColId(null)
131→                  }}
132→                  className="text-xs font-semibold text-[#555] uppercase tracking-wider bg-transparent border-b border-[#aaa] outline-none w-full"
133→                />
134→              ) : (
135→                <span
136→                  className="text-xs font-semibold text-[#888] uppercase tracking-wider cursor-pointer hover:text-[#555] transition-colors"
137→                  onDoubleClick={() => startEditCol(col)}
138→                  title="Double-click to rename"
139→                >
140→                  {col.label}
141→                </span>
142→              )}
143→              <span className="text-xs text-[#bbb] bg-[#ece9e3] px-1.5 py-0.5 rounded-full ml-2 shrink-0">
144→                {grouped[col.id].length}
145→              </span>
146→            </div>
147→            <div className="flex-1 overflow-y-auto space-y-2 pr-1">
148→              {grouped[col.id].map((c) => {
149→                const days = daysSince(c.last_contacted)
150→                const isSelected = c.id === selectedId
151→                return (
152→                  <div
153→                    key={c.id}
154→                    draggable
155→                    onDragStart={() => onDragStart(c)}
156→                    onClick={() => onSelect(c)}
157→                    className={`bg-white border rounded-xl p-3 cursor-grab active:cursor-grabbing transition-all shadow-sm select-none ${isSelected ? 'border-[#1a1a1a] shadow-md' : 'border-[#e8e6e1] hover:border-[#ccc] hover:shadow'}`}
158→                  >
159→                    <div className="flex items-center gap-2.5 mb-2">
160→                      <div className="w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-semibold shrink-0" style={{ background: avatarColor(c.name) }}>
161→                        {initials(c.name)}
162→                      </div>
163→                      <div className="min-w-0">
164→                        <p className="text-sm font-medium text-[#1a1a1a] truncate">{c.name}</p>
165→                        {c.company && <p className="text-[10px] text-[#aaa] truncate">{c.company}</p>}
166→                      </div>
167→                    </div>
168→                    {c.next_action && (
169→                      <p className="text-[11px] text-[#555] bg-amber-50 border border-amber-100 rounded-lg px-2 py-1 mb-2 line-clamp-2">{c.next_action}</p>
170→                    )}
171→                    <div className="flex items-center justify-between">
172→                      <div className="flex gap-1 flex-wrap">
173→                        {(c.tags || []).slice(0, 2).map((tag) => (
174→                          <span key={tag} className="text-[9px] text-[#999] bg-[#f0ede8] px-1.5 py-0.5 rounded-full">{tag}</span>
175→                        ))}
176→                      </div>
177→                      {days !== null && (
178→                        <span className={`text-[10px] font-medium ${days > 60 ? 'text-red-400' : days > 30 ? 'text-amber-400' : 'text-green-500'}`}>
179→                          {days}d
180→                        </span>
181→                      )}
182→                    </div>
183→                  </div>
184→                )
185→              })}
186→              {grouped[col.id].length === 0 && (
187→                <div className={`border-2 border-dashed rounded-xl p-4 text-center transition-colors ${dragOverColId === col.id ? 'border-[#aaa] bg-[#f7f5f2]' : 'border-[#e8e6e1]'}`}>
188→                  <p className="text-xs text-[#ccc]">Drop here</p>
189→                </div>
190→              )}
191→            </div>
192→          </div>
193→        ))}
194→      </div>
195→    </div>
196→  )
197→}
