 1→import { NextResponse } from 'next/server'
 2→import { exec } from 'child_process'
 3→import { existsSync, mkdirSync } from 'fs'
 4→import { getConfig, saveConfig } from '@/lib/config'
 5→
 6→export async function GET() {
 7→  return NextResponse.json(getConfig())
 8→}
 9→
10→export async function POST(req: Request) {
11→  try {
12→    const body = await req.json()
13→    if (body.contactsDir) {
14→      if (!existsSync(body.contactsDir)) {
15→        mkdirSync(body.contactsDir, { recursive: true })
16→      }
17→      const config = saveConfig({ contactsDir: body.contactsDir })
18→      return NextResponse.json(config)
19→    }
20→    if (body.action === 'open') {
21→      const dir = getConfig().contactsDir
22→      if (!existsSync(dir)) mkdirSync(dir, { recursive: true })
23→      exec(`open "${dir}"`)
24→      return NextResponse.json({ ok: true })
25→    }
26→    return NextResponse.json({ error: 'Unknown action' }, { status: 400 })
27→  } catch (err) {
28→    return NextResponse.json({ error: String(err) }, { status: 500 })
29→  }
30→}
